1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface Customer {
9	  yearsWithMHPCO: number;
10	}
11	
12	interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	interface Scenario {
18	  customer: Customer;
19	  steps: QuoteStep[];
20	}
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	};
29	
30	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
31	const COMPONENT_BASE = 25;
32	const BLOCK_SIZE = 3;
33	const BLOCK_BASE = 60;
34	
35	const FIRST_INSURANCE_RATE = 0.1;
36	const CURSE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_RATE = 0.3;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const LOYALTY_RATE = 0.2;
40	const LOYALTY_THRESHOLD = 2;
41	const FOLLOWUP_RATE = 0.15;
42	const PROCESSING_FEE = 5;
43	const ROUNDING_PRECISION = 6;
44	
45	const componentGroupBase = (count: number): number =>
46	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
47	
48	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
49	
50	const withSurcharge = (base: number, rate: number): number => base + base * rate;
51	
52	const isHighlyEnchanted = (item: Item): boolean =>
53	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
54	
55	const itemSurchargeRate = (item: Item): number =>
56	  FIRST_INSURANCE_RATE +
57	  (item.cursed ? CURSE_RATE : 0) +
58	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
59	
60	const mainItemPremium = (item: Item): number =>
61	  withSurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
62	
63	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
64	
65	const mainItemBaseSum = (items: Item[]): number =>
66	  mainItems(items).reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
67	
68	const mainItemTotal = (items: Item[]): number =>
69	  mainItems(items).reduce((sum, item) => sum + mainItemPremium(item), 0);
70	
71	const componentBaseSum = (items: Item[]): number => {
72	  const counts: Record<string, number> = {};
73	  for (const item of items.filter(isComponent)) {
74	    counts[item.type] = (counts[item.type] ?? 0) + 1;
75	  }
76	  return Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
77	};
78	
79	const componentTotal = (items: Item[]): number =>
80	  withSurcharge(componentBaseSum(items), FIRST_INSURANCE_RATE);
81	
82	const policyBase = (items: Item[]): number => mainItemBaseSum(items) + componentBaseSum(items);
83	
84	const policyDiscount = (items: Item[], rate: number, applies: boolean): number =>
85	  applies ? rate * policyBase(items) : 0;
86	
87	const loyaltyDiscount = (items: Item[], customer: Customer): number =>
88	  policyDiscount(items, LOYALTY_RATE, customer.yearsWithMHPCO >= LOYALTY_THRESHOLD);
89	
90	const followUpDiscount = (items: Item[], isFollowUp: boolean): number =>
91	  policyDiscount(items, FOLLOWUP_RATE, isFollowUp);
92	
93	const roundUpToWhole = (amount: number): number =>
94	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
95	
96	const itemPremiumSum = (items: Item[]): number =>
97	  mainItemTotal(items) + componentTotal(items);
98	
99	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number =>
100	  roundUpToWhole(
101	    itemPremiumSum(items) -
102	      loyaltyDiscount(items, customer) -
103	      followUpDiscount(items, isFollowUp) +
104	      PROCESSING_FEE,
105	  );
106	
107	const isQuote = (step: QuoteStep): boolean => step.op === "quote";
108	
109	const priorQuoteCount = (steps: QuoteStep[], index: number): number =>
110	  steps.slice(0, index).filter(isQuote).length;
111	
112	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
113	  const results = scenario.steps.map((step, index) => {
114	    const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
115	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
116	  });
117	  return { results };
118	};
